#!/usr/bin/env python3
"""
EduNet Python Curriculum Writer — Batch 6 (Final Python Batch)
Covers all remaining Python lessons:
- exception_handling: try_except_blocks, raising_exceptions, custom_exceptions
- file_handling_i_o: reading_files, writing_files, context_managers
- modules_packages: import_statements, python_standard_library, virtual_environments
- object_oriented_python: classes_instances, inheritance, polymorphism
- database_integration: sqlite_integration, sqlalchemy_orm, migration_scripts
"""

import json, os

BASE = os.path.join(os.path.dirname(__file__), '..', 'curriculum', 'python', 'modules')

def wjson(module, lesson, filename, data):
    p = os.path.join(BASE, module, lesson, 'locales', 'en', filename)
    os.makedirs(os.path.dirname(p), exist_ok=True)
    with open(p, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    print(f"  ✓ {module}/{lesson}/{filename}")

