wjson(M, L, 'project.json', { "title": "Embedded SQLite User Store", "tagline": "Persistent user repository", "description": "Build `UserStore` class providing `register()`, `authenticate()`, and `delete()` backed by SQLite.", "learningGoals": ["CRUD operations using sqlite3"], "requirements": ["Parameterized queries", "Password hashing check"], "starterCode": "class UserStore: pass", "solution": "import sqlite3\nclass UserStore:\n    def __init__(self, db_path=':memory:'):\n        self.conn = sqlite3.connect(db_path)\n        self.conn.execute('CREATE TABLE IF NOT EXISTS users (username TEXT PRIMARY KEY, password TEXT)')\n    def register(self, user, pwd):\n        try:\n            with self.conn:\n                self.conn.execute('INSERT INTO users VALUES (?, ?)', (user, pwd))\n            return True\n        except sqlite3.IntegrityError: return False", "solutionExpl": "Implements CRUD user repository with SQLite persistence.", "expectedOutput": "True", "extensions": ["Add password hashing via bcrypt/hashlib"] })
